-- Komprimierter Datenimport (2149 Einträge; Arzneistoffe als {name,amg:true})
-- In Supabase SQL Editor einfügen und Run. Ersetzt vorhandene Einträge (upsert).
insert into public.eintraege (id,kategorie,name,ampel,doc)
select x->>'id', x->>'kategorie', x->>'name', coalesce(x->>'ampel','gelb'), x
